// NQxb_Gateway__Freeze_Save_Context
// Freeze request fields BEFORE calling Save sub-workflow
// Tag for deterministic merge after sub-workflow returns
// This node splits to TWO destinations: Save sub-workflow + Merge bypass

return [{
  json: {
    ...$json,
    _merge_role: "frozen_context",
    _frozen_artifact_type: $json.req_artifact_type ?? $json.artifact_type ?? null,
    _frozen_workspace_id: $json.req_workspace_id ?? $json.gw_workspace_id ?? null,
    _frozen_extension: $json.req_extension ?? $json.extension ?? {},
  }
}];

// NQxb_Gateway__Tag_Save_Result
// Pure passthrough: Save sub-workflow response flows to webhook unmodified.
// Sapling A: No Gateway-level response modification permitted.

return [{ json: $json }];

// NQxb_Gateway_v1__Shape_List_Response
// Purpose: Shape canonical list response for Gateway
// Rule: If sub-workflow already returned a canonical artifact.list envelope,
//       PASS THROUGH exactly (no re-wrapping).

const j = $json ?? {};

// ---------- helpers ----------
const isObject = (x) => x && typeof x === "object" && !Array.isArray(x);

const isCanonicalListEnvelope = (x) =>
  isObject(x) &&
  x.ok === true &&
  x.gw_action === "artifact.list" &&
  isObject(x.data) &&
  Array.isArray(x.data.artifacts) &&
  isObject(x.meta);

// ---------- ERROR PASSTHROUGH (T112 fix) ----------
// If sub-workflow returned a validation error, pass it directly to the caller.
if (j.ok === false || j._gw_route === "error") {
  // Strip debug fields before returning to caller
  const { _debug_filters, ...clean } = j;
  return clean;
}

// ---------- PASS-THROUGH CASE ----------
// If Gateway received a single item in data.artifacts
// and that item is itself a canonical list envelope,
// return it directly.
if (
  isObject(j.data) &&
  Array.isArray(j.data.artifacts) &&
  j.data.artifacts.length === 1 &&
  isCanonicalListEnvelope(j.data.artifacts[0])
) {
  return j.data.artifacts[0];
}

// ---------- NORMAL WRAP (raw rows case) ----------
const artifacts = Array.isArray(j.data?.artifacts)
  ? j.data.artifacts
  : [];

return {
  ok: true,
  gw_action: "artifact.list",
  gw_workspace_id: j.gw_workspace_id,
  artifact_type: j.artifact_type,
  selector: j.selector ?? {},
  data: {
    artifacts,
  },
  meta: {
    count: artifacts.length,
    limit: j.selector?.limit ?? artifacts.length,
    offset: j.selector?.offset ?? 0,
    has_more: artifacts.length === (j.selector?.limit ?? artifacts.length),
    as_of: j.selector?.as_of ?? new Date().toISOString(),
  },
  timestamp: new Date().toISOString(),
};

// Normalize Gateway input for artifact.list before calling sub-workflow
// Purpose:
// - Ensure artifact_type is present at top level
// - Preserve selector object
// - Merge top-level limit/offset/hydrate/filters into selector (T19+T20 fix)
// - Prevent null / empty artifact_type from leaking downstream

const gw_workspace_id =
  $json.gw_workspace_id ??
  $json.req_workspace_id ??
  null;

if (!gw_workspace_id) {
  throw new Error("Gateway Build_List_Request: gw_workspace_id is required");
}

const artifact_type =
  (typeof $json.artifact_type === "string" && $json.artifact_type.trim() !== "")
    ? $json.artifact_type.trim()
    : (typeof $json.req_artifact_type === "string" && $json.req_artifact_type.trim() !== "")
      ? $json.req_artifact_type.trim()
      : null;

if (!artifact_type) {
  throw new Error("Gateway Build_List_Request: artifact_type is required for artifact.list");
}

// Build selector: prefer explicit selector object, then merge top-level fields
const selectorIn =
  (typeof $json.selector === "object" && $json.selector !== null)
    ? { ...$json.selector }
    : {};

// T20 FIX: Merge top-level limit/offset/hydrate into selector if not already present
if ($json.limit !== undefined && selectorIn.limit === undefined) {
  selectorIn.limit = $json.limit;
}
if ($json.offset !== undefined && selectorIn.offset === undefined) {
  selectorIn.offset = $json.offset;
}
if ($json.hydrate !== undefined && selectorIn.hydrate === undefined) {
  selectorIn.hydrate = $json.hydrate;
}

// T19 FIX: Merge top-level filters into selector.filters if not already present
if ($json.filters && typeof $json.filters === "object" && !selectorIn.filters) {
  selectorIn.filters = $json.filters;
}

return [
  {
    json: {
      gw_action: "artifact.list",
      gw_workspace_id,
      artifact_type,
      selector: selectorIn,

      // Debug breadcrumbs
      _gw_debug: {
        normalized: true,
        resolved_artifact_type: artifact_type,
        selector_had_limit: $json.selector?.limit !== undefined,
        top_level_limit: $json.limit,
        top_level_offset: $json.offset,
        top_level_filters: $json.filters ? true : false,
      },
    },
  },
];

// NQxb_Gateway_v1_Normalize_Update_Request
// Purpose: normalize artifact.update requests into a canonical update payload
// Runs AFTER Gateway action routing (artifact.update only)
// T87: Forward spine fields
// T140: Forward content, content_append, content_mode (title, summary, priority) — only when non-null

const input = $json ?? {};

// Canonical identifiers (already scalarized upstream)
const gw_workspace_id = input.gw_workspace_id ?? null;
const artifact_type = input.artifact_type ?? null;
const artifact_id = input.artifact_id ?? null;

// Payloads
const extension = input.extension ?? {};
const tags = input.tags ?? null;

// T140: Content fields for update
const content = (input.content && typeof input.content === "object" && !Array.isArray(input.content))
  ? input.content : null;
const content_append = (input.content_append && typeof input.content_append === "object" && !Array.isArray(input.content_append))
  ? input.content_append : null;
const content_mode = (typeof input.content_mode === "string" && input.content_mode.trim().length > 0)
  ? input.content_mode.trim() : null;

// T87: Only forward spine fields that have actual values (not null)
// The main Gateway normalizer sets missing fields to null — we must NOT forward those
// because the Update sub-workflow uses 'key in req' to detect intent
const spineFields = {};
if (input.title != null) spineFields.title = input.title;
if (input.summary != null) spineFields.summary = input.summary;
if (input.priority != null) spineFields.priority = input.priority;

// Detect source for debug only (no control flow dependency)
let source_detected = "unknown";
if ($json?.params) source_detected = "params";
else if ($json?.query) source_detected = "query";
else if ($json?.body?.body) source_detected = "body.body";
else if ($json?.body) source_detected = "body";
else source_detected = "json";

return [
  {
    json: {
      gw_action: "artifact.update",

      gw_workspace_id,
      artifact_type,
      artifact_id,

      extension,
      tags,

      // T140: Content fields
      ...(content !== null ? { content } : {}),
      ...(content_append !== null ? { content_append } : {}),
      ...(content_mode !== null ? { content_mode } : {}),

      // T87: Only non-null spine fields (spread so absent keys don't exist)
      ...spineFields,

      // Freeze intent for downstream workflows
      req_gw_workspace_id: gw_workspace_id,
      req_artifact_type: artifact_type,
      req_artifact_id: artifact_id,
      req_extension: extension,
      req_tags: tags,

      _gw_debug: {
        normalized_by: "NQxb_Gateway_v1_Normalize_Update_Request",
        source_detected,
        received_keys: Object.keys(input),
        has_extension: Object.keys(extension).length > 0,
        has_tags:
          tags &&
          ((Array.isArray(tags.add) && tags.add.length > 0) ||
            (Array.isArray(tags.remove) && tags.remove.length > 0)),
        has_content: content !== null,
        has_content_append: content_append !== null,
        has_content_mode: content_mode !== null,
        has_spine_fields: Object.keys(spineFields).length > 0,
        spine_field_keys: Object.keys(spineFields),
      },
    },
  },
];

// NQxb_Gateway_v1__Normalize_Promote_Request
// Purpose: Shape a promote request to match NQxb_Artifact_Promote_v1 Workflow Inputs contract.
// Notes:
// - Must output n8n items: [{ json: ... }]
// - Promote workflow expects transition/reason at TOP-LEVEL (due to current contract wiring)
// - We also preserve artifact_payload.transition/reason (future-proof / harmless)

const j = $json;

const transition = j.transition ?? j.artifact_payload?.transition ?? null;
const reason = j.reason ?? j.artifact_payload?.reason ?? null;

return [
  {
    json: {
      gw_action: j.gw_action,
      gw_workspace_id: j.gw_workspace_id,

      artifact_type: j.artifact_type,
      artifact_id: j.artifact_id,

      actor_user_id: j.actor?.user_id ?? j.actor_user_id ?? null,

      // ✅ REQUIRED by Promote workflow (current contract expectations)
      transition,
      reason,

      // ✅ keep payload too (harmless / future-proof)
      artifact_payload: {
        transition,
        reason,
      },

      selector: j.selector ?? {},
    },
  },
];

// NQxb_Gateway_v1__Shape_Query_Response
// Purpose: Gateway-level canonical envelope for artifact.query.
//
// HARD RULES:
// 1. Error envelopes MUST pass through unchanged.
// 2. Canonical success envelopes MUST pass through unchanged.
// 3. Only RAW artifacts may be wrapped.
// 4. No code path may ever convert an error into ok:true.

const j = $json ?? {};
const isObject = (v) => v && typeof v === "object" && !Array.isArray(v);

/* -------------------------------------------------
 * 1. PASS THROUGH ERRORS (ABSOLUTE)
 * ------------------------------------------------- */
if (
  j.ok === false ||
  j._gw_route === "error" ||
  isObject(j.error)
) {
  return [{ json: j }];
}

/* -------------------------------------------------
 * 2. PASS THROUGH CANONICAL SUCCESS
 * ------------------------------------------------- */
if (
  j.ok === true &&
  j._gw_route === "ok" &&
  isObject(j.data) &&
  isObject(j.data.artifact)
) {
  return [{ json: j }];
}

/* -------------------------------------------------
 * 3. UNWRAP RAW ARTIFACT
 * ------------------------------------------------- */
let raw = null;

// Common raw locations
if (isObject(j.artifact)) {
  raw = j.artifact;
} else if (isObject(j.data) && isObject(j.data.artifact)) {
  raw = j.data.artifact;
} else if (isObject(j)) {
  raw = j; // last resort
}

/* -------------------------------------------------
 * 4. WRAP EXACTLY ONCE
 * ------------------------------------------------- */
return [{
  json: {
    ok: true,
    _gw_route: "ok",
    data: {
      artifact: raw
    }
  }
}];

// Shape delete response
const result = $json;
const artifact = Array.isArray(result) ? result[0] : result;

if (!artifact || !artifact.artifact_id) {
  return [{
    json: {
      ok: false,
      gw_action: "artifact.delete",
      error: {
        code: "NOT_FOUND",
        message: "Artifact not found or already deleted"
      }
    }
  }];
}

return [{
  json: {
    ok: true,
    gw_action: "artifact.delete",
    artifact_id: artifact.artifact_id,
    title: artifact.title,
    deleted_at: artifact.deleted_at,
    message: "Artifact soft-deleted (can be restored)"
  }
}];

// Shape restore response
const result = $json;
const artifact = Array.isArray(result) ? result[0] : result;

if (!artifact || !artifact.artifact_id) {
  return [{
    json: {
      ok: false,
      gw_action: "artifact.restore",
      error: {
        code: "NOT_FOUND",
        message: "Artifact not found"
      }
    }
  }];
}

return [{
  json: {
    ok: true,
    gw_action: "artifact.restore",
    artifact_id: artifact.artifact_id,
    title: artifact.title,
    message: "Artifact restored"
  }
}];

// Shape list_deleted response
  const items = $items();
  const artifacts = items.map(item => item.json);

  return [{
    json: {
      ok: true,
      gw_action: "artifact.list_deleted",
      data: {
        artifacts
      },
      meta: {
        count: artifacts.length
      }
    }
  }];

const j = $json ?? {};
return [{
  json: {
    ok: false,
    _gw_route: 'error',
    gw_action: j.gw_action ?? null,
    gw_workspace_id: j.gw_workspace_id ?? null,
    artifact_type: j.artifact_type ?? null,
    error: {
      code: 'ACTION_NOT_ALLOWED',
      message: `Unrecognized gateway route or action. No handler matched.`,
      details: {
        gw_action: j.gw_action ?? null,
        _gw_route: j._gw_route ?? null,
        note: 'Switch fallback triggered — request did not match any configured route or action.'
      }
    },
    timestamp: new Date().toISOString()
  }
}];

// payload.build v1.1 — Intent → Canonical Payload Assembly
// Spec: Leaf 2.1 (eaf3c349) | Branch: 03fcfc9e
// v1.1: Fix double-nesting for snapshot/restart content.payload unwrap
const SPEC_VERSION = '1.1';

// ─── Type Rules (from Save v50 Check_Mutability_Rules + Validate_Request) ───

const TYPE_RULES = {
  project: {
    semantic_type: 'required',
    parent: 'optional',
    content_target: 'spine',
    extension_inject: { lifecycle_stage: 'seed' },
    extension_allowlist: ['lifecycle_stage', 'operational_state', 'state_reason', 'design_spine'],
  },
  journal: {
    semantic_type: 'required',
    parent: 'optional',
    content_target: 'extension.entry_text',
    content_type: 'string',
    extension_allowlist: ['entry_text'],
  },
  snapshot: {
    semantic_type: 'required',
    parent: 'optional',
    content_target: 'extension.payload',
    content_must_be_object: true,
    extension_allowlist: ['payload'],
  },
  restart: {
    semantic_type: 'required',
    parent: 'optional',
    content_target: 'extension.payload',
    content_must_be_object: true,
    extension_allowlist: ['payload'],
  },
  branch: {
    semantic_type: 'forbidden',
    parent: 'required',
    content_target: 'spine',
    extension_allowlist: [],
    default_execution_status: 'not_started',
  },
  leaf: {
    semantic_type: 'forbidden',
    parent: 'required',
    content_target: 'spine',
    extension_allowlist: [],
    default_execution_status: 'not_started',
  },
  limb: {
    semantic_type: 'forbidden',
    parent: 'required',
    content_target: 'spine',
    extension_allowlist: [],
    default_execution_status: 'not_started',
  },
  twig: {
    semantic_type: 'forbidden',
    parent: 'required',
    content_target: 'spine',
    extension_allowlist: [],
    default_execution_status: 'not_started',
    twig_content_required: true,
  },
  instruction_pack: {
    semantic_type: 'forbidden',
    parent: 'optional',
    content_target: 'spine',
    extension_allowlist: ['scope', 'active', 'priority', 'pack_format', 'payload'],
    extension_auto_created: true,
  },
  person: {
    semantic_type: 'required',
    parent: 'optional',
    content_target: 'extension_direct',
    extension_allowlist: [
      'full_name', 'preferred_name', 'relationship_type', 'status', 'pronouns',
      'personal_email', 'work_email', 'mobile_phone', 'work_phone', 'home_phone',
      'preferred_contact_method', 'preferred_contact_channel', 'timezone',
      'company', 'title', 'department', 'importance_level',
      'interaction_frequency', 'last_contacted_at', 'next_follow_up_at', 'do_not_contact',
      'address', 'communication_style', 'what_they_care_about', 'key_facts', 'preferences',
    ],
    person_required: ['full_name', 'preferred_name', 'relationship_type'],
  },
};

const SEMANTIC_TYPES = new Set([
  'governance', 'execution-core', 'infrastructure', 'platform',
  'product', 'alignment', 'sales', 'marketing', 'exploratory',
]);

const VALID_ACTIONS = new Set(['artifact.save', 'artifact.update', 'artifact.promote']);
const VALID_TRANSITIONS = new Set(['seed_to_sapling', 'sapling_to_tree', 'tree_to_archive']);
const CHILD_TYPES = new Set(['branch', 'leaf', 'limb', 'twig']);

// ─── Parse Intent ───

const raw = $input.first().json;
const workspace_id = raw.gw_workspace_id;

const intent = {
  action:        (raw.action || '').trim(),
  type:          (raw.type || raw.artifact_type || '').trim(),
  title:         (raw.title || '').trim(),
  artifact_id:   (raw.artifact_id || '').trim() || null,
  semantic_type: (raw.semantic_type || raw.semantic_type_id || '').trim() || null,
  priority:      raw.priority ?? null,
  tags:          raw.tags || null,
  parent:        (raw.parent || raw.parent_artifact_id || '').trim() || null,
  content:       raw.content ?? null,
  summary:       (raw.summary || '').trim() || null,
  transition:    (raw.transition || '').trim() || null,
  reason:        (raw.reason || '').trim() || null,
  mode:          (raw.mode || 'dry_run').trim(),
  extension:     raw.extension || null,
};

const errors = [];
const warnings = [];

// ─── Validate Action ───

if (!intent.action) {
  errors.push('Missing required field: action');
} else if (!VALID_ACTIONS.has(intent.action)) {
  errors.push(`Unknown action: "${intent.action}". Allowed: ${[...VALID_ACTIONS].join(', ')}`);
}

// ─── Validate Type ───

const typeRule = TYPE_RULES[intent.type];
if (!intent.type) {
  errors.push('Missing required field: type (artifact_type)');
} else if (!typeRule) {
  errors.push(`Unknown artifact_type: "${intent.type}". Allowed: ${Object.keys(TYPE_RULES).join(', ')}`);
}

// ─── Validate Mode ───

if (intent.mode !== 'dry_run' && intent.mode !== 'execute') {
  errors.push(`Invalid mode: "${intent.mode}". Allowed: dry_run, execute`);
}

// Short-circuit on fatal errors
if (errors.length > 0 || !typeRule) {
  return [{
    json: {
      ok: false,
      gw_action: 'payload.build',
      spec_version: SPEC_VERSION,
      mode: intent.mode,
      validation: { errors, warnings },
    }
  }];
}

// ─── Action-Specific Validation ───

if (intent.action === 'artifact.save') {

  // Title required on save
  if (!intent.title) {
    errors.push('Missing required field: title (required for save)');
  }

  // artifact_id forbidden on save
  if (intent.artifact_id) {
    errors.push('artifact_id is FORBIDDEN on save — server generates it');
  }

  // Semantic type
  if (typeRule.semantic_type === 'required') {
    if (!intent.semantic_type) {
      errors.push(`semantic_type is REQUIRED for artifact_type "${intent.type}"`);
    } else if (!SEMANTIC_TYPES.has(intent.semantic_type)) {
      errors.push(`Unknown semantic_type: "${intent.semantic_type}". Allowed: ${[...SEMANTIC_TYPES].join(', ')}`);
    }
  } else if (typeRule.semantic_type === 'forbidden' && intent.semantic_type) {
    errors.push(`semantic_type is FORBIDDEN for artifact_type "${intent.type}"`);
  }

  // Parent requirement
  if (typeRule.parent === 'required' && !intent.parent) {
    errors.push(`parent_artifact_id is REQUIRED for artifact_type "${intent.type}"`);
  }

  // Content validation per type
  if (typeRule.content_must_be_object && intent.content !== null) {
    // Unwrap content.payload if present (Q often pre-wraps)
    const effectiveContent = (intent.content && typeof intent.content === 'object'
      && !Array.isArray(intent.content) && intent.content.payload
      && typeof intent.content.payload === 'object' && !Array.isArray(intent.content.payload))
      ? intent.content.payload
      : intent.content;

    if (typeof effectiveContent !== 'object' || Array.isArray(effectiveContent)) {
      errors.push(`content must be an object for artifact_type "${intent.type}" (not string or array)`);
    } else if (Object.keys(effectiveContent).length === 0) {
      errors.push(`content must be non-empty for artifact_type "${intent.type}"`);
    }
  }

  // Journal: content should be string (maps to entry_text)
  if (intent.type === 'journal' && intent.content !== null) {
    if (typeof intent.content !== 'string') {
      errors.push('content must be a string for journal (maps to extension.entry_text)');
    } else if (intent.content.trim().length === 0) {
      errors.push('content (entry_text) must be non-empty for journal');
    }
  }

  // Twig content completeness
  if (typeRule.twig_content_required && intent.content) {
    const c = intent.content;
    if (typeof c === 'object' && !Array.isArray(c)) {
      const required = ['idea', 'why_now', 'problem_touched', 'future_hook'];
      for (const field of required) {
        if (!c[field] || (typeof c[field] === 'string' && c[field].trim().length === 0)) {
          errors.push(`Twig content requires non-empty field: "${field}"`);
        }
      }
    }
  }

  // Person required fields
  if (typeRule.person_required && intent.content) {
    const c = intent.content;
    if (typeof c === 'object' && !Array.isArray(c)) {
      for (const field of typeRule.person_required) {
        if (!c[field] || (typeof c[field] === 'string' && c[field].trim().length === 0)) {
          errors.push(`Person requires non-empty field: "${field}"`);
        }
      }
      // Validate JSONB array fields
      for (const arrField of ['key_facts', 'what_they_care_about', 'preferences']) {
        if (c[arrField] !== undefined && c[arrField] !== null && !Array.isArray(c[arrField])) {
          errors.push(`Person field "${arrField}" must be an array (or null)`);
        }
      }
      // Check unknown fields
      const allowedSet = new Set(typeRule.extension_allowlist);
      for (const key of Object.keys(c)) {
        if (!allowedSet.has(key)) {
          errors.push(`Unknown person field: "${key}". Not in extension allowlist.`);
        }
      }
      // Contact info warning
      const contactFields = ['personal_email', 'work_email', 'mobile_phone', 'work_phone', 'home_phone'];
      const hasContact = contactFields.some(f => c[f] && String(c[f]).trim().length > 0);
      if (!hasContact) {
        warnings.push('Person has no contact information; follow-up tracking may be limited');
      }
    }
  }

} else if (intent.action === 'artifact.update') {

  // artifact_id required on update
  if (!intent.artifact_id) {
    errors.push('Missing required field: artifact_id (required for update)');
  }
  if (!intent.type) {
    errors.push('Missing required field: type (required for update)');
  }

} else if (intent.action === 'artifact.promote') {

  // artifact_id required
  if (!intent.artifact_id) {
    errors.push('Missing required field: artifact_id (required for promote)');
  }
  // transition required
  if (!intent.transition) {
    errors.push('Missing required field: transition (required for promote)');
  } else if (!VALID_TRANSITIONS.has(intent.transition)) {
    errors.push(`Invalid transition: "${intent.transition}". Allowed: ${[...VALID_TRANSITIONS].join(', ')}`);
  }
  // reason required
  if (!intent.reason) {
    errors.push('Missing required field: reason (required for promote)');
  } else if (intent.reason.length > 280) {
    errors.push(`reason exceeds 280 characters (${intent.reason.length})`);
  }
}

// Warnings
if (!intent.tags || (Array.isArray(intent.tags) && intent.tags.length === 0)) {
  warnings.push('No tags provided (recommended but not required)');
}
if (intent.priority !== null && (intent.priority < 1 || intent.priority > 5)) {
  warnings.push(`Priority ${intent.priority} outside 1-5 range — will default to 3`);
}
if (intent.content === null && intent.action === 'artifact.save' &&
    !['branch', 'leaf', 'limb'].includes(intent.type)) {
  warnings.push('Content is empty (valid but unusual for this type)');
}

// ─── Early Return on Validation Errors ───

if (errors.length > 0) {
  return [{
    json: {
      ok: false,
      gw_action: 'payload.build',
      spec_version: SPEC_VERSION,
      mode: intent.mode,
      validation: { errors, warnings },
    }
  }];
}

// ─── Assemble Canonical Payload ───

const payload = {};

if (intent.action === 'artifact.save') {

  payload.gw_action = 'artifact.save';
  payload.gw_workspace_id = workspace_id;
  payload.artifact_type = intent.type;
  payload.title = intent.title;

  // Priority (default 3)
  payload.priority = (intent.priority !== null && intent.priority >= 1 && intent.priority <= 5)
    ? intent.priority : 3;

  // Summary
  if (intent.summary) {
    payload.summary = intent.summary;
  }

  // Tags (flat array on save)
  if (intent.tags && Array.isArray(intent.tags) && intent.tags.length > 0) {
    payload.tags = intent.tags;
  }

  // Semantic type (pass human key — Gateway Semantic_Resolver handles key→UUID)
  if (typeRule.semantic_type === 'required') {
    payload.semantic_type_id = intent.semantic_type;
  }

  // Parent
  if (intent.parent) {
    payload.parent_artifact_id = intent.parent;
  }

  // Content routing per type
  const target = typeRule.content_target;

  if (target === 'spine') {
    // Content goes to spine content field
    if (intent.content !== null && intent.content !== undefined) {
      payload.content = intent.content;
    }
    // Extension injection (e.g., project lifecycle_stage)
    if (typeRule.extension_inject) {
      payload.extension = { ...typeRule.extension_inject };
    }
    // Instruction pack: extension auto-created by trigger, don't send extension
    if (typeRule.extension_auto_created) {
      delete payload.extension;
    }

  } else if (target === 'extension.entry_text') {
    // Journal: string content → extension.entry_text
    payload.extension = { entry_text: intent.content };

  } else if (target === 'extension.payload') {
    // Snapshot/restart: object content → extension.payload
    // Unwrap content.payload if Q pre-wrapped it
    const payloadContent = (intent.content && typeof intent.content === 'object'
      && !Array.isArray(intent.content) && intent.content.payload
      && typeof intent.content.payload === 'object' && !Array.isArray(intent.content.payload))
      ? intent.content.payload
      : intent.content;
    payload.extension = { payload: payloadContent };

  } else if (target === 'extension_direct') {
    // Person: content fields map directly to extension fields
    if (intent.content && typeof intent.content === 'object') {
      payload.extension = {};
      const allowedSet = new Set(typeRule.extension_allowlist);
      for (const [key, val] of Object.entries(intent.content)) {
        if (allowedSet.has(key)) {
          payload.extension[key] = val;
        }
      }
    }
  }

  // Execution status default for child types
  if (typeRule.default_execution_status) {
    payload.execution_status = typeRule.default_execution_status;
  }

} else if (intent.action === 'artifact.update') {

  payload.gw_action = 'artifact.update';
  payload.gw_workspace_id = workspace_id;
  payload.artifact_type = intent.type;
  payload.artifact_id = intent.artifact_id;

  // Spine fields (only include if provided)
  if (intent.title) payload.title = intent.title;
  if (intent.summary) payload.summary = intent.summary;
  if (intent.priority !== null) payload.priority = intent.priority;

  // Tags (structured format for update)
  if (intent.tags) {
    if (Array.isArray(intent.tags)) {
      // Auto-convert flat array to add format
      payload.tags = { add: intent.tags };
    } else if (typeof intent.tags === 'object') {
      // Already structured { add: [], remove: [] }
      payload.tags = intent.tags;
    }
  }

  // Content (if provided)
  if (intent.content !== null && intent.content !== undefined) {
    payload.content = intent.content;
  }

  // Extension (passthrough if provided)
  if (intent.extension) {
    payload.extension = intent.extension;
  }

} else if (intent.action === 'artifact.promote') {

  payload.gw_action = 'artifact.promote';
  payload.gw_workspace_id = workspace_id;
  payload.artifact_type = intent.type;
  payload.artifact_id = intent.artifact_id;
  payload.transition = intent.transition;
  payload.reason = intent.reason;

}

// ─── Return Result ───

return [{
  json: {
    ok: true,
    gw_action: 'payload.build',
    spec_version: SPEC_VERSION,
    mode: intent.mode,
    target_action: intent.action,
    assembled_payload: payload,
    validation: { errors: [], warnings },
    _meta: {
      type_rule_applied: intent.type,
      content_target: typeRule ? typeRule.content_target : null,
      timestamp: new Date().toISOString(),
    },
  }
}];
